#!/usr/bin/env bash
set -euo pipefail
TARGET="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
echo "Applying to: $TARGET"
b64dec(){ base64 --decode 2>/dev/null || base64 -D; }
write(){ mkdir -p "$TARGET/$(dirname "$1")"; printf %s "$2" | b64dec > "$TARGET/$1"; }

write "CLAUDE.md" ""
write "index.html" ""
write "public/sitemap.xml" ""
write "src/App.tsx" ""
write "src/CLAUDE.md" ""
write "src/components/Footer.tsx" ""
write "src/components/NewRequest.tsx" ""
write "src/components/NotificationBell.tsx" ""
write "src/components/ReportProblem.tsx" ""
write "src/components/TopNav.tsx" ""
write "src/main.tsx" ""
write "src/pages/AdminDashboard.tsx" ""
write "src/pages/Blog.tsx" ""
write "src/pages/BlogPost.tsx" ""
write "src/pages/ClientDashboard.tsx" ""
write "src/pages/ClientOnboarding.tsx" ""
write "src/pages/ContractorDashboard.tsx" ""
write "src/pages/ContractorOnboarding.tsx" ""
write "src/pages/ContractorProfile.tsx" ""
write "src/pages/GetQuote.tsx" ""
write "src/pages/Home.tsx" ""
write "src/pages/PrivacyPolicy.tsx" ""
write "src/pages/UserAgreement.tsx" ""
write "supabase/CLAUDE.md" ""
write "supabase/functions/create-payment-intent/index.ts" ""
write "supabase/functions/stripe-webhook/index.ts" ""
write "src/components/GoogleReviewModal.tsx" ""
write "src/components/RespondToClaim.tsx" ""
write "src/lib/analytics.ts" ""
write "src/lib/reviewPrompt.ts" ""
write "src/pages/ForContractors.tsx" ""
write "src/pages/ServiceLanding.tsx" ""
write "src/pages/ServicesIndex.tsx" ""
write "supabase/migrations/20260627170000_replace_contractor_directory_view_with_functions.sql" ""

cd "$TARGET"
git add -A
git commit -m "Nav: menu for logged-in users (notifications/contact/logout), plain header logged-out" || echo "nothing to commit"
git push && echo "✅ pushed"
